script:
frappe.ui.form.on('Social Login Key', {
    refresh: function(frm) {
        // Add the button only if the document is not new
        if (!frm.is_new()) {
            frm.add_custom_button(__('Set as Default'), function() {
                frappe.confirm(
                    __('Are you sure you want this Social Login key to be default for Login?'),
                    function() {
                        // Action if "Yes" is clicked
                        frappe.call({
                            method: "connect_master.utils.set_default_social_login",
                            args: {
                                "name": frm.doc.name
                            },
                            callback: function(r) {
                                if (!r.exc) {
                                    frm.reload_doc();
                                    frappe.msgprint(__('Success: This is now the default login key.'));
                                }
                            }
                        });
                    }
                );
            }, __('Actions'));
        }
    }
});
